import React, { useState, useEffect } from "react";
import { Link } from "react-scroll";

import { AiOutlineMenu, AiOutlineClose } from 'react-icons/ai';

import '../styles/Header.css';

const headerItems = [
    {
        name: "Home",
        path: "home",
    },
    {
        name: "About",
        path: "about",
    },
    {
        name: "Work",
        path: "work",
    },
    {
        name: "Blog",
        path: "blog",
    },
    {
        name: "Contact",
        path: "contact",
    }
]

function getWindowSize() {
    const { innerWidth, innerHeight } = window;
    return { innerWidth, innerHeight };
}

function Header(props) {
    const [color, setColor] = useState("none");
    const [openMenu, setOpenMenu] = useState(false);

    const [windowSize, setWindowSize] = useState(getWindowSize());

    useEffect(() => {
        window.addEventListener("scroll", (event) => {
            if (window.scrollY >= window.innerHeight - 22) {
                setColor("rgba(41, 52, 72, 0.5)");
            } else {
                setColor("none");
            }
        })
        function handleWindowResize() {
            let size = getWindowSize();
            setWindowSize(size);
            if (size.innerWidth > 991) {
                setOpenMenu(false);
            }

        }

        window.addEventListener('resize', handleWindowResize);

        return () => {
            window.removeEventListener('resize', handleWindowResize);
        };
    }, [color])
    return (
        <>
            <div className="header" style={{
                background: color
            }}>
                {
                    headerItems.map((item, index) =>
                        <Link
                            key={index}
                            to={item.path}
                            style={{
                                borderBottomColor: props.active === item.path ? "var(--red)" : ""
                            }}
                            className="headerLink"
                            spy={true}
                            smooth={true}
                            duration={300}
                        >
                            {item.name}
                        </Link>
                    )
                }
            </div>
            <AiOutlineMenu className="burgerMenu" fill="#fff"
                style={{
                    background: color,
                    display: (openMenu || windowSize.innerWidth > 991) ? "none" : "block"
                }} onClick={() => setOpenMenu(true)} />

            <AiOutlineClose className="burgerMenu" fill="#fff"
                style={{ display: openMenu ? "block" : "none" }} onClick={() => setOpenMenu(false)} />
            <div className="headerRes" style={{ display: openMenu ? "flex" : "none" }}>
                {
                    headerItems.map((item, index) =>
                        <Link
                            key={index}
                            to={item.path}
                            style={{
                                color: props.active === item.path ? "var(--red)" : ""
                            }}
                            className="headerLinkRes"
                            spy={true}
                            smooth={true}
                            duration={300}
                            onClick={() => setTimeout(() => { setOpenMenu(false) }, 500)}
                        >
                            {item.name}
                        </Link>
                    )
                }
            </div>
        </>
    );
}

export default Header;
